import { Platform } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const API_BASE_URL = 'https://api.example.com';
const AUTH_TOKEN_KEY = '@auth_token';
const REFRESH_TOKEN_KEY = '@refresh_token';

class ApiService {
  constructor() {
    this.authToken = null;
    this.refreshToken = null;
  }

  async init() {
    try {
      this.authToken = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
      this.refreshToken = await AsyncStorage.getItem(REFRESH_TOKEN_KEY);
    } catch (error) {
      console.error('Failed to load tokens:', error);
    }
  }

  async setAuthTokens(authToken, refreshToken) {
    this.authToken = authToken;
    this.refreshToken = refreshToken;
    try {
      await AsyncStorage.setItem(AUTH_TOKEN_KEY, authToken);
      if (refreshToken) {
        await AsyncStorage.setItem(REFRESH_TOKEN_KEY, refreshToken);
      }
    } catch (error) {
      console.error('Failed to save tokens:', error);
    }
  }

  async clearAuthTokens() {
    this.authToken = null;
    this.refreshToken = null;
    try {
      await AsyncStorage.removeItem(AUTH_TOKEN_KEY);
      await AsyncStorage.removeItem(REFRESH_TOKEN_KEY);
    } catch (error) {
      console.error('Failed to clear tokens:', error);
    }
  }

  getHeaders(includeAuth = true, customHeaders = {}) {
    const headers = {
      'Content-Type': 'application/json',
      'Accept': 'application/json',
      'User-Agent': `MyApp/${Platform.OS}`,
      ...customHeaders,
    };

    if (includeAuth && this.authToken) {
      headers['Authorization'] = `Bearer ${this.authToken}`;
    }

    return headers;
  }

  async request(endpoint, options = {}) {
    const url = `${API_BASE_URL}${endpoint}`;
    const config = {
      ...options,
      headers: this.getHeaders(options.includeAuth !== false, options.headers),
    };

    try {
      const response = await fetch(url, config);
      
      if (response.status === 401 && this.refreshToken) {
        const refreshed = await this.refreshAuthToken();
        if (refreshed) {
          config.headers = this.getHeaders(true, options.headers);
          const retryResponse = await fetch(url, config);
          return this.handleResponse(retryResponse);
        } else {
          await this.clearAuthTokens();
          throw new Error('Session expired. Please login again.');
        }
      }

      return this.handleResponse(response);
    } catch (error) {
      if (error.message === 'Network request failed') {
        throw new Error('Network error. Please check your connection.');
      }
      throw error;
    }
  }

  async handleResponse(response) {
    const contentType = response.headers.get('content-type');
    let data;

    if (contentType && contentType.includes('application/json')) {
      data = await response.json();
    } else {
      data = await response.text();
    }

    if (!response.ok) {
      const error = new Error(data.message || `HTTP Error: ${response.status}`);
      error.status = response.status;
      error.data = data;
      throw error;
    }

    return data;
  }

  async refreshAuthToken() {
    try {
      const response = await fetch(`${API_BASE_URL}/auth/refresh`, {
        method: 'POST',
        headers: this.getHeaders(false),
        body: JSON.stringify({ refreshToken: this.refreshToken }),
      });

      if (response.ok) {
        const data = await response.json();
        await this.setAuthTokens(data.authToken, data.refreshToken || this.refreshToken);
        return true;
      }
      return false;
    } catch (error) {
      console.error('Token refresh failed:', error);
      return false;
    }
  }

  async login(email, password) {
    const data = await this.request('/auth/login', {
      method: 'POST',
      includeAuth: false,
      body: JSON.stringify({ email, password }),
    });

    if (data.authToken) {
      await this.setAuthTokens(data.authToken, data.refreshToken);
    }

    return data;
  }

  async register(userData) {
    const data = await this.request('/auth/register', {
      method: 'POST',
      includeAuth: false,
      body: JSON.stringify(userData),
    });

    if (data.authToken) {
      await this.setAuthTokens(data.authToken, data.refreshToken);
    }

    return data;
  }

  async logout() {
    try {
      await this.request('/auth/logout', {
        method: 'POST',
      });
    } catch (error) {
      console.error('Logout request failed:', error);
    } finally {
      await this.clearAuthTokens();
    }
  }

  async getUserProfile() {
    return this.request('/user/profile', {
      method: 'GET',
    });
  }

  async updateUserProfile(profileData) {
    return this.request('/user/profile', {
      method: 'PUT',
      body: JSON.stringify(profileData),
    });
  }

  async updateUserAvatar(imageUri) {
    const formData = new FormData();
    const filename = imageUri.split('/').pop();
    const match = /\.(\w+)$/.exec(filename);
    const type = match ? `image/${match[1]}` : 'image/jpeg';

    formData.append('avatar', {
      uri: Platform.OS === 'ios' ? imageUri.replace('file://', '') : imageUri,
      name: filename,
      type,
    });

    return this.request('/user/avatar', {
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      body: formData,
    });
  }

  async changePassword(oldPassword, newPassword) {
    return this.request('/user/password', {
      method: 'PUT',
      body: JSON.stringify({ oldPassword, newPassword }),
    });
  }

  async deleteAccount() {
    await this.request('/user/account', {
      method: 'DELETE',
    });
    await this.clearAuthTokens();
  }

  async getData(endpoint, params = {}) {
    const queryString = Object.keys(params)
      .map(key => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`)
      .join('&');
    
    const url = queryString ? `${endpoint}?${queryString}` : endpoint;
    
    return this.request(url, {
      method: 'GET',
    });
  }

  async postData(endpoint, data) {
    return this.request(endpoint, {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async putData(endpoint, data) {
    return this.request(endpoint, {
      method: 'PUT',
      body: JSON.stringify(data),
    });
  }

  async patchData(endpoint, data) {
    return this.request(endpoint, {
      method: 'PATCH',
      body: JSON.stringify(data),
    });
  }

  async deleteData(endpoint) {
    return this.request(endpoint, {
      method: 'DELETE',
    });
  }

  isAuthenticated() {
    return !!this.authToken;
  }

  async resetPassword(email) {
    return this.request('/auth/reset-password', {
      method: 'POST',
      includeAuth: false,
      body: JSON.stringify({ email }),
    });
  }

  async verifyResetToken(token, newPassword) {
    return this.request('/auth/verify-reset', {
      method: 'POST',
      includeAuth: false,
      body: JSON.stringify({ token, newPassword }),
    });
  }

  async uploadFile(endpoint, fileUri, fieldName = 'file', additionalData = {}) {
    const formData = new FormData();
    const filename = fileUri.split('/').pop();
    const match = /\.(\w+)$/.exec(filename);
    const type = match ? `application/${match[1]}` : 'application/octet-stream';

    formData.append(fieldName, {
      uri: Platform.OS === 'ios' ? fileUri.replace('file://', '') : fileUri,
      name: filename,
      type,
    });

    Object.keys(additionalData).forEach(key => {
      formData.append(key, additionalData[key]);
    });

    return this.request(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'multipart/form-data',
      },
      body: formData,
    });
  }
}

const apiService = new ApiService();

export default apiService;